// Assign each new item to a cluster based on keyword similarity.
// This is a lightweight in-memory clustering pass that does not require
// an AI call. The AI classification step may refine cluster_label later.
//
// Strategy: sliding window of cluster_label candidates.
// Items sharing a strong keyword overlap with an existing cluster are merged.
// New clusters are created when no match is found above the threshold.

const input = $input.first().json;
const items = Array.isArray(input.items) ? input.items : [];

const SIMILARITY_THRESHOLD = 2; // minimum shared keywords to merge into a cluster

const tokenize = (text) =>
  (text || '')
    .toLowerCase()
    .replace(/[^a-z0-9\s]/g, ' ')
    .split(/\s+/)
    .filter(t => t.length > 3);

const clusters = []; // [{ label, keywords: Set, itemIndexes: [] }]

const clustered = items.map((item, idx) => {
  const tokens = new Set(tokenize(`${item.headline} ${item.body || ''}`));

  // Find best matching existing cluster
  let bestMatch = null;
  let bestScore = 0;
  for (const cluster of clusters) {
    const shared = [...tokens].filter(t => cluster.keywords.has(t)).length;
    if (shared > bestScore) {
      bestScore = shared;
      bestMatch = cluster;
    }
  }

  if (bestMatch && bestScore >= SIMILARITY_THRESHOLD) {
    // Merge into existing cluster
    for (const t of tokens) bestMatch.keywords.add(t);
    bestMatch.itemIndexes.push(idx);
    return { ...item, cluster_label: bestMatch.label };
  }

  // Create new cluster — use first 5 meaningful words as label
  const labelWords = [...tokens].slice(0, 5).join(' ');
  const label = labelWords || item.headline.slice(0, 60);
  clusters.push({ label, keywords: tokens, itemIndexes: [idx] });
  return { ...item, cluster_label: label };
});

return [{ json: { items: clustered, cluster_count: clusters.length } }];
